sp_header_footer.css:
.idpbob-footer {
    background-color: var(--carbon-ui-01);
    border-top: 1px solid var(--carbon-ui-03);
    padding: var(--carbon-spacing-07) var(--carbon-spacing-06);
    margin-top: var(--carbon-spacing-09);
    color: var(--carbon-text-02);
}

.idpbob-footer-content {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: var(--carbon-spacing-05);
}

.idpbob-footer-links {
    display: flex;
    gap: var(--carbon-spacing-06);
    flex-wrap: wrap;
}

.idpbob-footer-link {
    color: var(--carbon-link-01);
    text-decoration: none;
    font-size: 14px;
}

.idpbob-footer-link:hover {
    color: var(--carbon-hover-primary-text);
    text-decoration: underline;
}

.idpbob-footer-copyright {
    font-size: 12px;
    color: var(--carbon-text-03);
}

.idpbob-footer-social {
    display: flex;
    gap: var(--carbon-spacing-04);
}

.idpbob-footer-social-link {
    color: var(--carbon-text-02);
    font-size: 18px;
    transition: color 0.11s cubic-bezier(0.2, 0, 0.38, 0.9);
}

.idpbob-footer-social-link:hover {
    color: var(--carbon-interactive-01);
}

@media (max-width: 768px) {
    .idpbob-footer-content {
        flex-direction: column;
        text-align: center;
    }

    .idpbob-footer-links {
        flex-direction: column;
        gap: var(--carbon-spacing-03);
    }
}
